// Build a SDXL Lightning ComfyUI workflow JSON from the request.
// Input (JSON body): { prompt, negative?, width?, height?, steps?, seed?, model?, batch_size? }
// Mirrors docker-compose.base.yml COMFYUI_WORKFLOW so Open WebUI and Agents share the same model.
const body = $input.first().json.body || $input.first().json;
const prompt = (body.prompt || '').toString();
if (!prompt) { throw new Error('Missing required field: prompt'); }

const negative   = (body.negative || '').toString();
const width      = parseInt(body.width      ?? 1024, 10);
const height     = parseInt(body.height     ?? 1024, 10);
const steps      = parseInt(body.steps      ?? 4,    10);
const seed       = parseInt(body.seed       ?? Math.floor(Math.random() * 2 ** 31), 10);
const batch_size = parseInt(body.batch_size ?? 1,    10);
const model      = (body.model || 'sdxl_lightning_4step.safetensors').toString();

const workflow = {
  "3": { "inputs": { seed, steps, cfg: 1.5, sampler_name: "euler", scheduler: "sgm_uniform", denoise: 1.0, model: ["4", 0], positive: ["6", 0], negative: ["7", 0], latent_image: ["5", 0] }, "class_type": "KSampler" },
  "4": { "inputs": { ckpt_name: model }, "class_type": "CheckpointLoaderSimple" },
  "5": { "inputs": { width, height, batch_size }, "class_type": "EmptyLatentImage" },
  "6": { "inputs": { text: prompt,   clip: ["4", 1] }, "class_type": "CLIPTextEncode" },
  "7": { "inputs": { text: negative, clip: ["4", 1] }, "class_type": "CLIPTextEncode" },
  "8": { "inputs": { samples: ["3", 0], vae: ["4", 2] }, "class_type": "VAEDecode" },
  "9": { "inputs": { filename_prefix: "n8n-agent", images: ["8", 0] }, "class_type": "SaveImage" }
};

return [{ json: { client_id: `n8n-${Date.now()}`, prompt: workflow, _params: { prompt, negative, width, height, steps, seed, model, batch_size } } }];

// Extract the first generated image from ComfyUI history response.
// History format: { "<prompt_id>": { outputs: { "9": { images: [{ filename, subfolder, type }] } }, ... } }
const history = $input.first().json;
const entry   = Object.values(history)[0];
if (!entry || !entry.outputs) { throw new Error('ComfyUI returned no outputs'); }
const outputs = entry.outputs;
const saveNode = Object.values(outputs).find(o => Array.isArray(o.images) && o.images.length);
if (!saveNode) { throw new Error('No SaveImage output in ComfyUI history'); }
const img = saveNode.images[0];
// Build query string manually — URLSearchParams is not available in n8n Code node sandbox.
const qs = `filename=${encodeURIComponent(img.filename)}&subfolder=${encodeURIComponent(img.subfolder || '')}&type=${encodeURIComponent(img.type || 'output')}`;
// internal_url: container-to-container, used by the next HTTP node.
// public_url:   returned to the caller. Adjust this hardcoded host:port if you
//               move ComfyUI off this machine — n8n Code sandbox blocks env access.
const publicBase = 'http://192.168.178.110:8188';
const internal_url = `http://comfyui:8188/view?${qs}`;
const public_url   = `${publicBase}/view?${qs}`;
return [{ json: { image_url: public_url, internal_url, filename: img.filename, subfolder: img.subfolder, type: img.type } }];

// Build OpenAI-Images-like response: { created, data: [{ b64_json, url }] }
// In a Code node, the previous HTTP node (responseFormat: file) leaves the
// PNG bytes in $binary.data — we read them via the helpers API.
const meta = $('Extract Image URL').first().json;
let b64 = '';
try {
  const buf = await this.helpers.getBinaryDataBuffer(0, 'data');
  b64 = Buffer.isBuffer(buf) ? buf.toString('base64') : '';
} catch (e) {
  // Fall back silently — the public URL is still returned and usable.
}
return [{ json: { created: Math.floor(Date.now() / 1000), data: [{ b64_json: b64, url: meta.image_url, filename: meta.filename }] } }];
